INSERT INTO `therapists` VALUES
(1,'Hj. Dewi Irvani','S.Hut, MCHt, CI, MPh, MSI','Founder Albashiroh Islamic Hypnotherapy | Spiritual Hypnotherapist & Trauma Healing Expert','therapist-1.jpg','Sebagai pendiri Albashiroh, Hj. Dewi Irvani adalah praktisi hipnoterapi berpengalaman lebih dari 10 tahun. Beliau mensinergikan psikologi modern dengan nilai spiritual Islam untuk terapi holistik yang menyentuh akar masalah. Tujuannya membimbing jiwa untuk pulang, membersihkan hati, dan meraih ketenangan sejati bersama Allah SWT.','MCHt (Master Clinical Hypnotherapist)\n\n, CI (Certified Instructor), Instruktur Resmi LKP THETA INSTITUTE OF CLINICAL HYPNOTHERAPY',12,0,'2025-12-25 08:46:26','2026-02-24 05:49:10'),
(2,'Siti Muzayanah','SPd.I, C.H, C.H.Kids, C.MH, C.Ht, C.MMH','Konseling Keluarga & Anak-Anak | Islamic Family & Child Therapist','therapist-2.jpg','Sebagai konselor keluarga, Siti Muzayanah berdedikasi penuh pada kesehatan mental anak dan keharmonisan rumah tangga. Beliau memadukan teknik hipnoterapi klinis dengan pendidikan karakter Islami untuk pemulihan yang lembut. Visinya membangun kembali pondasi keluarga sakinah dan mencetak generasi muda yang tenang hatinya bersama Allah SWT.','Certified Child Hypnotherapist (Hipnoterapi Khusus Anak), Terapis Keluarga Bersertifikat, C.MMH (Certified Master Medical Hypnosis), Praktisi Pendidikan & Konseling Islam',8,1,'2025-12-25 08:46:26','2026-02-01 01:57:38'),
(3,'Ira Suryandari','CH.Kids, CH.HBirth, CHt','Konseling Wanita & Keluarga | Islamic Family & Child Therapist','therapist-3.jpg','Sebagai terapis profesional, Ira Suryandari fokus pada kesehatan mental wanita dan persiapan kelahiran (hypnobirthing). Beliau menyediakan ruang aman bagi muslimah untuk berbagi dengan pendekatan penuh empati. Metodenya menyatukan teknik hipnoterapi modern dan nilai Islami demi meraih solusi terbaik serta ketenangan jiwa bersama Allah SWT.','Certified Hypnobirthing (CH.HBirth - Praktisi Hipnoterapi Kelahiran), Certified Hypnotherapy for Kids (CH.Kids - Spesialis Hipnoterapi Anak), Certified Hypnotherapist (CHt)',6,1,'2025-12-25 08:46:26','2026-01-10 14:17:11');
